import json
from pathlib import Path

# Build an alert-to-runbook registry from a runbooks/ directory.
# Each runbook is a Markdown file with YAML front matter.
import re

def parse_frontmatter(content: str) -> dict:
    """Extract YAML-style front matter from a Markdown file."""
    match = re.match(r'^---\n(.*?)\n---', content, re.DOTALL)
    if not match:
        return {}
    fm = {}
    for line in match.group(1).splitlines():
        if ':' in line:
            key, _, value = line.partition(':')
            fm[key.strip()] = value.strip()
    return fm


def build_runbook_registry(runbooks_dir: str = "runbooks") -> dict:
    registry = {}
    for path in Path(runbooks_dir).glob("*.md"):
        text = path.read_text()
        fm = parse_frontmatter(text)
        alert_name = fm.get("alert")
        runbook_url = fm.get("url")
        if alert_name and runbook_url:
            registry[alert_name] = {
                "url": runbook_url,
                "severity": fm.get("severity", "P2"),
                "team": fm.get("team", "unknown"),
                "file": str(path),
            }
    return registry


if __name__ == "__main__":
    registry = build_runbook_registry()
    print(json.dumps(registry, indent=2))
    # Example output:
    # {
    #   "AgentHighErrorRate": {
    #     "url": "https://runbooks.internal/agent-high-error-rate",
    #     "severity": "P1",
    #     "team": "agent-platform",
    #     "file": "runbooks/agent-high-error-rate.md"
    #   },
    #   ...
    # }
